import{_ as t,o as s,c as a,a3 as o}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"36. Transition Of All Other Employees","description":"","frontmatter":{"title":"36. Transition Of All Other Employees","eba":"Health Allied & Managers Admin 2021-2025","topics":["classifications"]},"headers":[],"relativePath":"ebas/has-managers-admin/health-allied-services/classification-staffing/36-transition-of-all-other-employees.md","filePath":"ebas/has-managers-admin/health-allied-services/classification-staffing/36-transition-of-all-other-employees.md"}'),r={name:"ebas/has-managers-admin/health-allied-services/classification-staffing/36-transition-of-all-other-employees.md"};function n(i,e,l,p,c,m){return s(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="_36-transition-of-all-other-employees" tabindex="-1">36. Transition Of All Other Employees <a class="header-anchor" href="#_36-transition-of-all-other-employees" aria-label="Permalink to &quot;36. Transition Of All Other Employees&quot;">​</a></h1><p><strong>36.1</strong> Employees who are classified as All Other Employees (not provided for elsewhere) will be reclassified to appropriate classifications no later than 12 months from the commencement date of this Agreement.</p><p><strong>36.2</strong> From the commencement date of this Agreement the classification All Other Employees (not provided for elsewhere) will not be used to:</p><p><strong>(a)</strong> classify new employees;</p><p>SECTION 2 – HEALTH &amp; ALLIED SERVICES EMPLOYEES AND DENTAL ASSISTANTS</p><p><strong>(b)</strong> classify employees transferring from other health services covered by this agreement; or</p><p><strong>(c)</strong> to reclassify existing employees under this Agreement.</p><p><strong>36.3</strong> It is anticipated that this correction will create a financial cost in the event the Employee was under classified having regard to their substantive duties.</p><p><strong>36.4</strong> Employees classified as All Other Employees (not provided for elsewhere) at the commencement of this Agreement who:</p><p><strong>(a)</strong> are engaged in work for COVID-19 purposes;</p><p><strong>(b)</strong> are not able to be classified in any other more-appropriate classification under this Agreement;</p><p><strong>(c)</strong> will remain on that classification until the COVID-19 pandemic ceases.</p><p><strong>36.5</strong> Any employee who is seconded from an existing role in a health service to work in a COVID-19 setting will be paid at their substantive classification for all time worked.</p><p><strong>36.6</strong> Employees who take on additional hours in a COVID-19 setting may be paid at separate rates according to the work undertaken. These may include:</p><p><strong>(a)</strong> Dual-role employees;</p><p><strong>(b)</strong> Part time employees;</p><p><strong>(c)</strong> Casual employees.</p>',17)])])}const f=t(r,[["render",n]]);export{d as __pageData,f as default};
